63	      ? maxImagesPerCallRaw.bind(model)
64	      : maxImagesPerCallRaw;
65	
66	  return {
67	    specificationVersion: 'v3',
68	    provider: providerId ?? overrideProvider?.({ model }) ?? model.provider,
69	    modelId: modelId ?? overrideModelId?.({ model }) ?? model.modelId,
70	    maxImagesPerCall,
71	    async doGenerate(
72	      params: ImageModelV3CallOptions,
73	    ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
