```typescript
import { InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The art style for the generated image.
         * - 'pixel': Classic pixelated look
         * - 'retro': Retro/vintage pixel aesthetic
         * - '8bit': 8-bit video game style
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),
        /**
         * Pixel density (pixels per unit). Controls how blocky/fine the
         * pixel grid is. Range 1–100, where lower = larger pixels.
         */
        pixelDensity: z.number().min(1).max(100).nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<typeof pixelartImageModelOptionsSchema>;
```

---

### Step 10 — `packages/pixelart/src/pixelart-image-model.ts`

Core implementation of `ImageModelV3`. API call pattern:
- **Endpoint**: `POST https://api.pixelart.ai/v1/images/generate`
- **Request body**: `{ model, prompt, n, size, seed, style?, pixel_density? }`
- **Response**: `{ created: number, data: [{ b64_json: string }] }` — returns base64 images directly (no URL-download step needed)
- **Error schema**: `{ error: { message: string, type: string, code: string } }`

```typescript
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]):
    Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {

    const { prompt, n, size, seed, providerOptions, abortSignal, headers } = options;
    const warnings: SharedV3Warning[] = [];

    // Parse provider-specific options (pixelart.style, pixelart.pixelDensity)
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      seed,
    };

    if (size != null) {
      requestBody.size = size;          // pass through as "WxH" string
    }
    if (pixelartOptions?.style != null) {
      requestBody.style = pixelartOptions.style;
    }
    if (pixelartOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelartOptions.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: requestBody,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelartImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    // Decode base64 strings → Uint8Array
    const images = value.data.map(item =>
      Buffer.from(item.b64_json, 'base64'),
    );

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Zod response schema
const pixelartImageResponseSchema = z.object({
  created: z.number(),
  data: z.array(z.object({ b64_json: z.string() })),
});

// Zod error schema
const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: error => error.error.message,
});
```

---

### Step 11 — `packages/pixelart/src/pixelart-provider.ts`

Factory function using simple object pattern (same as fal, not the callable-function pattern used by openai). Only `imageModel` and `image` are exposed. All other model types (`languageModel`, `embeddingModel`) throw `NoSuchModelError`.

```typescript
export interface PixelArtProviderSettings {
  /** API key. Default: PIXELART_API_KEY env var. */
  apiKey?: string;
  /** Override base URL. Default: 'https://api.pixelart.ai/v1' */
  baseURL?: string;
  /** Additional headers. */
  headers?: Record<string, string>;
  /** Custom fetch implementation. */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const unsupported = (modelType: string) => (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: unsupported('languageModel'),
    embeddingModel: unsupported('embeddingModel'),
    textEmbeddingModel: unsupported('embeddingModel'),
  };
}

export const pixelart = createPixelArt();
```

> **Note**: `loadApiKey` from `@ai-sdk/provider-utils` handles env-var loading and throws a descriptive error if missing — no need for the custom inline version used by fal.

---

### Step 12 — `packages/pixelart/src/index.ts`

