- **Response**: `{ created: number, data: [{ b64_json: string }] }` — returns base64 images directly (no URL-download step needed)
- **Error schema**: `{ error: { message: string, type: string, code: string } }`

```typescript
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]):
    Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {

    const { prompt, n, size, seed, providerOptions, abortSignal, headers } = options;
    const warnings: SharedV3Warning[] = [];

    // Parse provider-specific options (pixelart.style, pixelart.pixelDensity)
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      seed,
    };

    if (size != null) {
      requestBody.size = size;          // pass through as "WxH" string
    }
    if (pixelartOptions?.style != null) {
      requestBody.style = pixelartOptions.style;
    }
    if (pixelartOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelartOptions.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: requestBody,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelartImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    // Decode base64 strings → Uint8Array
    const images = value.data.map(item =>
      Buffer.from(item.b64_json, 'base64'),
    );

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Zod response schema
const pixelartImageResponseSchema = z.object({
  created: z.number(),
  data: z.array(z.object({ b64_json: z.string() })),
});

// Zod error schema
const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: error => error.error.message,
});
```

