import { NoSuchModelError } from '@ai-sdk/provider';
import { describe, expect, it } from 'vitest';
import { createPixelArt, pixelart } from './pixelart-provider';
import { PixelArtImageModel } from './pixelart-image-model';

describe('createPixelArt', () => {
  it('should return a provider with specificationVersion v3', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(provider.specificationVersion).toBe('v3');
  });

  it('should create an image model via image()', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.image('pixelart/standard');
    expect(model).toBeInstanceOf(PixelArtImageModel);
    expect(model.modelId).toBe('pixelart/standard');
  });

  it('should create an image model via imageModel()', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.imageModel('pixelart/retro');
    expect(model).toBeInstanceOf(PixelArtImageModel);
    expect(model.modelId).toBe('pixelart/retro');
  });

  it('should create an image model for all built-in model IDs', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const modelIds = ['pixelart/standard', 'pixelart/retro', 'pixelart/8bit'];
    for (const modelId of modelIds) {
      const model = provider.image(modelId);
      expect(model.modelId).toBe(modelId);
      expect(model.provider).toBe('pixelart.image');
    }
  });

  it('should accept custom model IDs', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.image('pixelart/custom-model');
    expect(model.modelId).toBe('pixelart/custom-model');
  });

  it('should throw NoSuchModelError for languageModel()', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.languageModel('gpt-4')).toThrowError(
      NoSuchModelError,
    );
  });

  it('should throw NoSuchModelError for embeddingModel()', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.embeddingModel('text-embed')).toThrowError(
      NoSuchModelError,
    );
  });

  it('should use custom baseURL when provided', () => {
    const provider = createPixelArt({
      apiKey: 'test-key',
      baseURL: 'https://custom.example.com/api',
    });
    // Creating a model should succeed with the custom base URL
    const model = provider.image('pixelart/standard');
    expect(model).toBeInstanceOf(PixelArtImageModel);
  });

  it('should use custom headers when provided', () => {
    const provider = createPixelArt({
      apiKey: 'test-key',
      headers: { 'X-Custom-Header': 'custom-value' },
    });
    const model = provider.image('pixelart/standard');
    expect(model).toBeInstanceOf(PixelArtImageModel);
  });
});

describe('pixelart default instance', () => {
  it('should be a pre-created provider instance', () => {
    // The default instance is created at module load time.
    // We verify it has the expected shape without calling it
    // (API key would be missing in test environment).
    expect(pixelart).toBeDefined();
    expect(pixelart.specificationVersion).toBe('v3');
    expect(typeof pixelart.image).toBe('function');
    expect(typeof pixelart.imageModel).toBe('function');
  });
});

